import { useCategoricalBarChartBaseConfig } from './useCategoricalBarChartBaseConfig.js';
import type { ChartUnit } from '../../core/types/chart-unit.js';
import type { ValueRepresentation } from '../../core/types/scales.js';
import { getRelativeValue } from '../../core/utils/get-relative-value.js';
import { safeGet } from '../../core/utils/safe-get.js';
import type {
  CategoricalBarData,
  WeakMapCategory,
  WeakMapDimension,
} from '../types/categorical-bar-chart-data.js';
import { isStacked } from '../utils/layout.js';

export type MinMaxPerUnit = Map<ChartUnit, { min: number; max: number }>;

export const getMaxDimensionValue = (
  filteredCategories: CategoricalBarData[],
): number =>
  Math.max(
    ...filteredCategories.map((category) =>
      category.dimensions.length > 0
        ? Math.abs(category.dimensions[0].value)
        : 0,
    ),
  );

export const calculateTotalCategoryValue = (
  categoryData: CategoricalBarData,
): number =>
  categoryData.dimensions.reduce(
    (total, dimension) => total + Math.abs(dimension.value),
    0,
  );

export const calculateRelativeValue = (
  value: unknown,
  relativeTotalValue?: number,
): number => {
  const numericValue = Number(value);
  const numberValue = isNaN(numericValue) ? 0 : numericValue;

  return relativeTotalValue
    ? getRelativeValue(numberValue, relativeTotalValue)
    : numberValue;
};

/**
 *
 * @param filteredCategories - filtered categories that have new reference in memory, so would throw an error if we do safeGet on it
 * @param categoricalData - non filtered categories that have their obj reference in the category/dimension map
 * @param categoryMap - category map
 * @param dimensionMap  - dimension map
 * @returns
 */
export function useGenerateFilteredCategoricalBarData(
  filteredCategories: CategoricalBarData[],
  categoricalData: CategoricalBarData[],
  unit: ChartUnit,
  categoryMap: WeakMapCategory,
  dimensionMap: WeakMapDimension,
  valueRepresentation: ValueRepresentation,
) {
  const { groupMode } = useCategoricalBarChartBaseConfig();

  const filteredUniqueDimensions = new Set<string>();
  const minMaxPerUnit: MinMaxPerUnit = new Map();
  let isSingleDimension = true;

  for (const filteredCategory of filteredCategories) {
    const { id: categoryId, dimensions: filteredDimensions } = filteredCategory;

    if (filteredDimensions.length > 1) {
      isSingleDimension = false;
    }

    const categoryObjReference = categoricalData.find(
      (p) => p.id === categoryId,
    );

    const categoryMetadata = safeGet(categoryMap, categoryObjReference);

    let relativeTotalValue: number | undefined = undefined;

    if (valueRepresentation === 'relative') {
      relativeTotalValue = isSingleDimension
        ? getMaxDimensionValue(filteredCategories)
        : calculateTotalCategoryValue(filteredCategory);
    }

    const cumulativeRanges = [0, 0];
    for (const dimension of filteredDimensions) {
      const dimensionObjReference = categoryObjReference?.dimensions.find(
        (d) => d.name === dimension.name,
      );

      const dimensionMetadata = safeGet(dimensionMap, dimensionObjReference);

      let { value } = dimensionMetadata;

      if (valueRepresentation === 'relative') {
        value = calculateRelativeValue(dimension.value, relativeTotalValue);
      }

      let cumulativeValue = 0;

      if (isStacked(groupMode)) {
        const NEGATIVE_RANGE = 0;
        const POSITIVE_RANGE = 1;
        const rangeIndex = value < 0 ? NEGATIVE_RANGE : POSITIVE_RANGE;
        cumulativeValue = cumulativeRanges[rangeIndex];
        cumulativeRanges[rangeIndex] += value;
      }

      filteredUniqueDimensions.add(dimension.name);
      dimensionMetadata.value = value;
      dimensionMetadata.cumulativeValue = cumulativeValue;
      dimensionMap.set(dimension, dimensionMetadata);

      const valueToMinMax = (cumulativeValue ?? 0) + value;

      const currentMinMax = minMaxPerUnit.get(unit);

      if (!currentMinMax) {
        minMaxPerUnit.set(unit, {
          min: valueToMinMax,
          max: valueToMinMax,
        });
      } else {
        minMaxPerUnit.set(unit, {
          min: Math.min(currentMinMax.min, valueToMinMax),
          max: Math.max(currentMinMax.max, valueToMinMax),
        });
      }
    }

    categoryMap.set(filteredCategory, categoryMetadata);
  }

  return {
    categoryMap,
    dimensionMap,
    filteredUniqueDimensions: Array.from(filteredUniqueDimensions),
    minMaxPerUnit,
    isSingleDimension,
  };
}
